// TestBuildUsageReturnsNilWhenNoEntries guarantees the no-fabrication rule
// for AC 2: absence of session data yields null usage, not zero-valued counts.
func TestBuildUsageReturnsNilWhenNoEntries(t *testing.T) {
	now := time.Now().UTC()
	u := buildUsage(nil, "anything", agent.MatchProvider, now)
	if u != nil {
		t.Fatalf("expected nil usage when there are no entries, got %+v", u)
	}
	// One entry that doesn't match the requested name should also yield nil.
	entries := []agent.SessionIndexEntry{{
		ID: "x", Harness: "claude", Provider: "anthropic",
		StartedAt: now.Add(-10 * time.Minute), Tokens: 123, Outcome: "success",
	}}
	u = buildUsage(entries, "other-name", agent.MatchProvider, now)
	if u != nil {
		t.Fatalf("expected nil usage when no entry matches name, got %+v", u)
	}
}

// TestHarnessStatusesFromInfosUsesDirectDTOFields verifies the harness row is
// now populated directly from HarnessInfo instead of the rate-limit cache.
func TestHarnessStatusesFromInfosUsesDirectDTOFields(t *testing.T) {
	now := time.Date(2026, 4, 24, 5, 0, 0, 0, time.UTC)
	infos := []agentlib.HarnessInfo{{
		Name:                "claude",
		Type:                "subprocess",
		Available:           true,
		AutoRoutingEligible: true,
		DefaultModel:        "claude-sonnet-4-6",
		CostClass:           "subscription",
		Account: &agentlib.AccountStatus{
			Authenticated: true,
			Source:        "account-source",
			CapturedAt:    now.Add(-5 * time.Minute),
		},
		Quota: &agentlib.QuotaState{
			Status:     "stale",
			Fresh:      false,
			Source:     "quota-source",
			CapturedAt: now.Add(-4 * time.Minute),
		},
		UsageWindows: []agentlib.UsageWindow{
			{
				Name:         "7d",
				Source:       "usage-7d",
				CapturedAt:   now.Add(-3 * time.Minute),
				InputTokens:  11,
				OutputTokens: 7,
				TotalTokens:  18,
			},
			{
				Name:         "30d",
				Source:       "usage-30d",
				CapturedAt:   now.Add(-2 * time.Minute),
				InputTokens:  31,
				OutputTokens: 19,
				TotalTokens:  50,
			},
		},
	}}

	rows := harnessStatusesFromInfos(infos, nil, now)
	if len(rows) != 1 {
		t.Fatalf("expected one harness row, got %d", len(rows))
	}
	row := rows[0]
	if row.Model != "claude-sonnet-4-6" {
		t.Fatalf("model = %q, want direct default model", row.Model)
	}
	if row.Quota != nil {
		t.Fatalf("quota should stay nil without direct HarnessInfo quota windows, got %+v", row.Quota)
	}
	if row.Status != "available" || !row.Reachable {
		t.Fatalf("status/reachable = %q/%v, want available/true", row.Status, row.Reachable)
	}
	if row.Detail == "" {
		t.Fatal("detail must be populated from HarnessInfo")
	}
	if row.LastCheckedAt == nil || *row.LastCheckedAt != "2026-04-24T05:00:00Z" {
		t.Fatalf("lastCheckedAt = %v, want direct timestamp", row.LastCheckedAt)
	}
	if row.RecentWorkerCount != 0 {
		t.Fatalf("recentWorkerCount = %d, want 0 with no sessions", row.RecentWorkerCount)
	}
	if row.Usage != nil {
		t.Fatalf("usage should be nil without matching session rows, got %+v", row.Usage)
	}
}

// TestProviderTrendProjectionFromSeededUsageAndCeiling seeds ascending usage
// and a real rate-limit-derived ceiling, then asserts ProviderTrend returns a
// positive ProjectedRunOutHours. Covers AC 3 "projection renders only when
// ceiling is known and last-24h slope is positive."
func TestProviderTrendProjectionFromSeededUsageAndCeiling(t *testing.T) {
	harnessRateLimitCache.Lock()
	harnessRateLimitCache.byName = make(map[string]agent.RateLimitSignal)
	harnessRateLimitCache.Unlock()
	t.Cleanup(func() {
		harnessRateLimitCache.Lock()
		harnessRateLimitCache.byName = make(map[string]agent.RateLimitSignal)
		harnessRateLimitCache.Unlock()
	})

	workDir := t.TempDir()
	writeMinimalConfig(t, workDir)

	// Seed ascending hourly usage for the last 24h under harness=claude.
	now := time.Now().UTC()
	for i := 0; i < 24; i++ {
		t0 := now.Add(-time.Duration(24-i) * time.Hour).Add(30 * time.Minute)
		appendSessionForTest(t, workDir, agent.SessionIndexEntry{
			ID: fmt.Sprintf("proj-%d", i), Harness: "claude", Provider: "anthropic",
			StartedAt: t0, Tokens: 1000 + i*200, Outcome: "success",
		}, t0)
	}
	// Record a ceiling via the rate-limit cache (10,000 tokens remaining).
	sig := agent.RateLimitSignal{
		CeilingTokens:        50000,
		CeilingWindowSeconds: 60,
		Remaining:            10000,
		ResetAt:              time.Time{},
	}
	name := strings.TrimSpace("claude")
	if name != "" && sig.HasAny() {
		harnessRateLimitCache.Lock()
		harnessRateLimitCache.byName[name] = sig
		harnessRateLimitCache.Unlock()
	}

	r := &queryResolver{Resolver: &Resolver{WorkingDir: workDir}}
	trend, err := r.ProviderTrend(context.Background(), "claude", 7)
	if err != nil {
		t.Fatalf("ProviderTrend: %v", err)
	}
	if trend.CeilingTokens == nil || *trend.CeilingTokens != 50000 {
