777					AttemptID:          res.AttemptID,
778					WorkerID:           res.WorkerID,
779					Harness:            res.Harness,
780					Provider:           res.Provider,
781					Model:              res.Model,
782					ActualPower:        res.ActualPower,
783					Status:             res.Status,
784					Detail:             res.Detail,
785					SessionID:          res.SessionID,
786					BaseRev:            res.BaseRev,
787					ResultRev:          res.ResultRev,
788					PreserveRef:        res.PreserveRef,
789					NoChangesRationale: res.NoChangesRationale,
790					CostUSD:            res.CostUSD,
791					DurationMS:         int64(res.DurationMS),
792				}, nil
793			}
794	
795			// Cost-cap state for this worker run. Subscription / local providers do
796			// not contribute (see escalation.CountsTowardCostCap).
797			// TODO(ddx-785d02f7): expose maxCostUSD as a worker spec field
798			// once the spec config knob lands.
799			var ladderOnce sync.Once
800			var ladder *tierescalation.Ladder
801			loadLadder := func() *tierescalation.Ladder {
802				ladderOnce.Do(func() {
803					ladder = tierescalation.NewLadder(nil)
804					if svc, svcErr := agent.NewServiceFromWorkDir(projectRoot); svcErr == nil {
805						modelFilter := agentlib.ModelFilter{}
806						if harness := rcfg.Harness(); harness != "" {
807							modelFilter.Harness = harness
808						}
809						modelCtx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
810						defer cancel()
811						if models, listErr := svc.ListModels(modelCtx, modelFilter); listErr == nil {
812							ladder = tierescalation.NewLadder(models)
813						}
814					}
815				})
816				return ladder
817			}
818			costCap = policyescalation.NewCostCapTracker(policyescalation.DefaultMaxCostUSD, func(harnessName string) bool {
819				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
820				if svcErr != nil {
821					return true
822				}
823				infos, err := svc.ListHarnesses(context.Background())
824				if err != nil {
825					return true
826				}
827				for _, h := range infos {
828					if h.Name == harnessName {
829						return policyescalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
830					}
831				}
832				return true
833			})
834			accumulateBilledCost := func(report agent.ExecuteBeadReport) {
835				costCap.Add(report.Harness, report.CostUSD)
836			}
837			costCapTripped := func() (agent.ExecuteBeadReport, bool) {
838				if _, tripped := costCap.Tripped(); !tripped {
839					return agent.ExecuteBeadReport{}, false
840				}
841				spent := costCap.Spent()
842				return agent.ExecuteBeadReport{
843					Status: agent.ExecuteBeadStatusExecutionFailed,
844					Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, policyescalation.DefaultMaxCostUSD),
845				}, true
846			}
847			attemptWithCostCap := func(ctx context.Context, beadID string, requestedMinPower int) (agent.ExecuteBeadReport, error) {
848				if cappedReport, capped := costCapTripped(); capped {
849					cappedReport.BeadID = beadID
850					return cappedReport, nil
851				}
852				report, err := singleTierAttempt(ctx, beadID, requestedMinPower, spec.Harness, spec.Provider, spec.Model)
853				if err == nil {
854					accumulateBilledCost(report)
855					if cappedReport, capped := costCapTripped(); capped {
856						cappedReport.BeadID = beadID
857						return cappedReport, nil
858					}
859				}
860				return report, err

380		}
381		if row.RecentWorkerCount != 0 {
382			t.Fatalf("recentWorkerCount = %d, want 0 with no sessions", row.RecentWorkerCount)
383		}
384		if row.Usage != nil {
385			t.Fatalf("usage should be nil without matching session rows, got %+v", row.Usage)
386		}
