389	// TestProviderTrendProjectionFromSeededUsageAndCeiling seeds ascending usage
390	// and a real rate-limit-derived ceiling, then asserts ProviderTrend returns a
391	// positive ProjectedRunOutHours. Covers AC 3 "projection renders only when
392	// ceiling is known and last-24h slope is positive."
393	func TestProviderTrendProjectionFromSeededUsageAndCeiling(t *testing.T) {
394		harnessRateLimitCache.Lock()
395		harnessRateLimitCache.byName = make(map[string]agent.RateLimitSignal)
396		harnessRateLimitCache.Unlock()
397		t.Cleanup(func() {
398			harnessRateLimitCache.Lock()
399			harnessRateLimitCache.byName = make(map[string]agent.RateLimitSignal)
400			harnessRateLimitCache.Unlock()
401		})
402	
403		workDir := t.TempDir()
404		writeMinimalConfig(t, workDir)
405	
406		// Seed ascending hourly usage for the last 24h under harness=claude.
407		now := time.Now().UTC()
408		for i := 0; i < 24; i++ {
409			t0 := now.Add(-time.Duration(24-i) * time.Hour).Add(30 * time.Minute)
410			appendSessionForTest(t, workDir, agent.SessionIndexEntry{
411				ID: fmt.Sprintf("proj-%d", i), Harness: "claude", Provider: "anthropic",
412				StartedAt: t0, Tokens: 1000 + i*200, Outcome: "success",
413			}, t0)
414		}
415		// Record a ceiling via the rate-limit cache (10,000 tokens remaining).
416		sig := agent.RateLimitSignal{
417			CeilingTokens:        50000,
418			CeilingWindowSeconds: 60,
419			Remaining:            10000,
420			ResetAt:              time.Time{},
421		}
422		name := strings.TrimSpace("claude")
423		if name != "" && sig.HasAny() {
424			harnessRateLimitCache.Lock()
425			harnessRateLimitCache.byName[name] = sig
426			harnessRateLimitCache.Unlock()
427		}
428	
429		r := &queryResolver{Resolver: &Resolver{WorkingDir: workDir}}
430		trend, err := r.ProviderTrend(context.Background(), "claude", 7)
431		if err != nil {
432			t.Fatalf("ProviderTrend: %v", err)
433		}
434		if trend.CeilingTokens == nil || *trend.CeilingTokens != 50000 {
435			t.Fatalf("expected ceiling 50000, got %+v", trend.CeilingTokens)
436		}
437		if trend.ProjectedRunOutHours == nil || *trend.ProjectedRunOutHours <= 0 {
438			t.Fatalf("expected positive ProjectedRunOutHours, got %+v", trend.ProjectedRunOutHours)
439		}
440	}
